import { useState, useEffect } from "react";
import { C, API_URL } from "../shared/constants";
import { Card, Btn, KPI, PageHeader, Toast } from "../shared/ui";

const Reportes = ({ onBack }) => {
  const [ordenes, setOrdenes]       = useState([]);
  const [asistencia, setAsistencia] = useState([]);
  const [horasExtra, setHorasExtra] = useState([]);
  const [loading, setLoading]       = useState(false);
  const [toast, setToast]           = useState(null);
  const [tab, setTab]               = useState("resumen");
  const [descargando, setDescargando] = useState(null);

  const hoy = new Date().toISOString().split("T")[0];
  const inicioMes = new Date(new Date().getFullYear(), new Date().getMonth(), 1)
    .toISOString().split("T")[0];
  const [fechaInicio, setFechaInicio] = useState(inicioMes);
  const [fechaFin, setFechaFin]       = useState(hoy);

  const cargar = async () => {
    setLoading(true);
    try {
      const [ords, asist, extra] = await Promise.all([
        fetch(`${API_URL}/ordenes`).then(x => x.json()).catch(() => []),
        fetch(`${API_URL}/asistencia/detalle?fecha=${hoy}`).then(x => x.json()).catch(() => []),
        fetch(`${API_URL}/reportes/horas-extra?fecha_inicio=${fechaInicio}&fecha_fin=${fechaFin}`)
          .then(x => x.json()).catch(() => []),
      ]);
      setOrdenes(Array.isArray(ords) ? ords : []);
      setAsistencia(Array.isArray(asist) ? asist : []);
      setHorasExtra(Array.isArray(extra) ? extra : []);
    } catch {}
    setLoading(false);
  };

  useEffect(() => { cargar(); }, []);

  // Calculos del periodo seleccionado
  const ordenesMes = ordenes.filter(o => {
    const f = (o.fecha_creacion || "").split("T")[0];
    return f >= fechaInicio && f <= fechaFin;
  });
  const cerradas   = ordenesMes.filter(o => o.estado === "cerrada");
  const noEjec     = ordenesMes.filter(o => o.estado === "no_ejecutada");
  const enCurso    = ordenesMes.filter(o => ["en_curso","fachada","inspeccion","ejecucion"].includes(o.estado));
  const eficiencia = ordenesMes.length > 0 ? Math.round((cerradas.length / ordenesMes.length) * 100) : 0;
  const durProm    = cerradas.length > 0
    ? Math.round(cerradas.reduce((a, o) => a + (o.duracion_min || 0), 0) / cerradas.length)
    : 0;
  const totalExtra = horasExtra.reduce((a, h) => a + (h.total_a_pagar || 0), 0);

  const fmt = n => new Intl.NumberFormat("es-CO", { style: "currency", currency: "COP", maximumFractionDigits: 0 }).format(n || 0);

  const exportarCSV = (datos, nombre) => {
    if (!datos.length) { setToast({ msg: "No hay datos para exportar", type: "error" }); return; }
    const keys = Object.keys(datos[0]);
    const csv = [keys.join(","), ...datos.map(row =>
      keys.map(k => `"${String(row[k] ?? "").replace(/"/g, '""')}"`).join(",")
    )].join("\n");
    const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url; a.download = `${nombre}-${fechaInicio}-${fechaFin}.csv`; a.click();
    URL.revokeObjectURL(url);
    setToast({ msg: "CSV exportado", type: "success" });
  };

  const descargarPDFOrden = async (ord) => {
    setDescargando(ord.id);
    try {
      const res = await fetch(`${API_URL}/ordenes/${ord.id}/reporte-pdf`);
      if (!res.ok) throw new Error();
      const blob = await res.blob();
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url; a.download = `reporte-${ord.consecutivo}.pdf`; a.click();
      URL.revokeObjectURL(url);
      setToast({ msg: `PDF ${ord.consecutivo} descargado`, type: "success" });
    } catch { setToast({ msg: "Error al generar PDF", type: "error" }); }
    finally { setDescargando(null); }
  };

  const tabS = (t) => ({
    padding: "8px 18px", borderRadius: 8, cursor: "pointer", fontSize: 12, fontWeight: 700,
    background: tab === t ? C.dark : C.bg, color: tab === t ? "#fff" : C.muted,
    border: `1px solid ${tab === t ? C.dark : C.border}`,
  });

  const thS = { padding: "10px 12px", textAlign: "left", fontWeight: 700, fontSize: 10,
    color: C.muted, borderBottom: `1px solid ${C.border}`, whiteSpace: "nowrap" };
  const tdS = (i) => ({ padding: "9px 12px", background: i % 2 === 0 ? "white" : C.bg + "80",
    borderBottom: `1px solid ${C.border}` });

  return (
    <div>
      {toast && <Toast {...toast} onClose={() => setToast(null)} />}
      <PageHeader title="Reportes y KPIs" subtitle="Analisis del periodo" onBack={onBack} />

      {/* Filtro fechas */}
      <Card style={{ marginBottom: 20 }}>
        <div style={{ display: "flex", alignItems: "flex-end", gap: 14, flexWrap: "wrap" }}>
          <div>
            <div style={{ fontSize: 11, fontWeight: 700, color: C.muted, marginBottom: 4 }}>DESDE</div>
            <input type="date" value={fechaInicio} onChange={e => setFechaInicio(e.target.value)}
              style={{ padding: "8px 12px", border: `1px solid ${C.border}`, borderRadius: 8, fontSize: 13, fontFamily: "inherit" }} />
          </div>
          <div>
            <div style={{ fontSize: 11, fontWeight: 700, color: C.muted, marginBottom: 4 }}>HASTA</div>
            <input type="date" value={fechaFin} onChange={e => setFechaFin(e.target.value)}
              style={{ padding: "8px 12px", border: `1px solid ${C.border}`, borderRadius: 8, fontSize: 13, fontFamily: "inherit" }} />
          </div>
          <Btn onClick={cargar} disabled={loading} style={{ padding: "9px 20px" }}>
            {loading ? "Cargando..." : "ACTUALIZAR"}
          </Btn>
        </div>
      </Card>

      {/* KPIs */}
      <div style={{ display: "flex", gap: 12, marginBottom: 20, flexWrap: "wrap" }}>
        <KPI label="SERVICIOS"     value={ordenesMes.length}  color={C.accent} />
        <KPI label="COMPLETADOS"   value={cerradas.length}    color="#06D6A0" />
        <KPI label="NO EJECUTADOS" value={noEjec.length}      color="#EF4444" />
        <KPI label="EFICIENCIA"    value={`${eficiencia}%`}   color="#8B5CF6" />
        <KPI label="TIEMPO PROM."  value={durProm > 0 ? `${Math.floor(durProm/60)}h ${durProm%60}m` : "-"} color="#F59E0B" />
        <KPI label="EXTRAS"        value={fmt(totalExtra)}    color={C.dark} />
      </div>

      {/* Tabs */}
      <div style={{ display: "flex", gap: 8, marginBottom: 20, flexWrap: "wrap" }}>
        {[["resumen","Resumen"],["servicios","Servicios"],["asistencia","Asistencia hoy"],["horas","Horas Extra"]].map(([k, l]) => (
          <div key={k} onClick={() => setTab(k)} style={tabS(k)}>{l}</div>
        ))}
      </div>

      {/* TAB RESUMEN */}
      {tab === "resumen" && (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(260px, 1fr))", gap: 14 }}>
          <Card>
            <div style={{ fontWeight: 700, fontSize: 13, color: C.muted, marginBottom: 14 }}>SERVICIOS POR ESTADO</div>
            {[
              ["Pendientes",    ordenes.filter(o=>o.estado==="pendiente").length, "#94A3B8"],
              ["En curso",      enCurso.length, "#F59E0B"],
              ["Cerradas",      cerradas.length, "#06D6A0"],
              ["No ejecutadas", noEjec.length, "#EF4444"],
            ].map(([lbl, val, col]) => (
              <div key={lbl} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <div style={{ width: 8, height: 8, borderRadius: "50%", background: col }} />
                  <span style={{ fontSize: 13 }}>{lbl}</span>
                </div>
                <span style={{ fontWeight: 800, color: col, fontSize: 16 }}>{val}</span>
              </div>
            ))}
          </Card>

          <Card>
            <div style={{ fontWeight: 700, fontSize: 13, color: C.muted, marginBottom: 14 }}>POR TIPO DE SERVICIO</div>
            {["montaje","desmontaje","ambos"].map(tipo => {
              const cnt = ordenesMes.filter(o => o.tipo_servicio === tipo).length;
              const pct = ordenesMes.length > 0 ? Math.round(cnt / ordenesMes.length * 100) : 0;
              return (
                <div key={tipo} style={{ marginBottom: 12 }}>
                  <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, marginBottom: 4 }}>
                    <span style={{ textTransform: "capitalize", fontWeight: 600 }}>{tipo}</span>
                    <span style={{ fontWeight: 700 }}>{cnt} ({pct}%)</span>
                  </div>
                  <div style={{ height: 6, borderRadius: 3, background: C.border }}>
                    <div style={{ height: 6, borderRadius: 3, width: `${pct}%`, background: C.accent, transition: "width 0.4s" }} />
                  </div>
                </div>
              );
            })}
          </Card>

          <Card>
            <div style={{ fontWeight: 700, fontSize: 13, color: C.muted, marginBottom: 14 }}>HORAS EXTRA PERIODO</div>
            <div style={{ fontSize: 28, fontWeight: 900, color: C.dark, marginBottom: 4 }}>{horasExtra.length}</div>
            <div style={{ fontSize: 12, color: C.muted, marginBottom: 12 }}>registros</div>
            <div style={{ padding: "10px 12px", background: C.bg, borderRadius: 8, border: `1px solid ${C.border}` }}>
              <div style={{ fontSize: 11, color: C.muted, marginBottom: 2 }}>TOTAL A PAGAR</div>
              <div style={{ fontWeight: 800, fontSize: 16 }}>{fmt(totalExtra)}</div>
            </div>
          </Card>

          <Card>
            <div style={{ fontWeight: 700, fontSize: 13, color: C.muted, marginBottom: 14 }}>EXPORTAR DATOS</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
              <Btn variant="ghost" style={{ textAlign: "left", fontSize: 12 }}
                onClick={() => exportarCSV(ordenesMes.map(o => ({
                  consecutivo: o.consecutivo, estado: o.estado, tipo: o.tipo_servicio,
                  cliente: o.cliente_nombre, referencia: o.referencia_nombre,
                  tecnico: o.tecnico_nombre || "", duracion_min: o.duracion_min || 0,
                  fecha: (o.fecha_creacion || "").split("T")[0]
                })), "servicios")}>
                Servicios del periodo (.csv)
              </Btn>
              <Btn variant="ghost" style={{ textAlign: "left", fontSize: 12 }}
                onClick={() => exportarCSV(horasExtra.map(h => ({
                  empleado: h.empleado, fecha: h.fecha,
                  horas_diurnas: h.horas_extra_diurnas, horas_nocturnas: h.horas_extra_nocturnas,
                  valor_diurno: h.valor_diurno, valor_nocturno: h.valor_nocturno, total: h.total_a_pagar
                })), "horas-extra")}>
                Horas extra (.csv)
              </Btn>
              <Btn variant="ghost" style={{ textAlign: "left", fontSize: 12 }}
                onClick={() => exportarCSV(asistencia.map(a => ({
                  usuario: a.usuario, tipo_marca: a.tipo_marca, hora: a.hora,
                  placa: a.placa || "", es_extra: a.es_extra ? "Si" : "No"
                })), "asistencia")}>
                Asistencia del dia (.csv)
              </Btn>
            </div>
          </Card>
        </div>
      )}

      {/* TAB SERVICIOS */}
      {tab === "servicios" && (
        <div>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
            <div style={{ fontSize: 13, color: C.muted }}>{ordenesMes.length} orden(es) en el periodo</div>
            <Btn variant="ghost" style={{ fontSize: 11 }}
              onClick={() => exportarCSV(ordenesMes.map(o => ({
                consecutivo: o.consecutivo, estado: o.estado, tipo: o.tipo_servicio,
                cliente: o.cliente_nombre, referencia: o.referencia_nombre,
                tecnico: o.tecnico_nombre || "", duracion_min: o.duracion_min || 0,
                fecha: (o.fecha_creacion || "").split("T")[0]
              })), "servicios")}>
              Exportar CSV
            </Btn>
          </div>
          <Card>
            <div style={{ overflowX: "auto" }}>
              <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
                <thead>
                  <tr style={{ background: C.bg }}>
                    {["OS","Estado","Tipo","Cliente","Referencia","Tecnico","Duracion","Fecha",""].map(h => (
                      <th key={h} style={thS}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {ordenesMes.length === 0 && (
                    <tr><td colSpan={9} style={{ padding: 24, textAlign: "center", color: C.muted }}>Sin ordenes en el periodo seleccionado</td></tr>
                  )}
                  {ordenesMes.map((o, i) => {
                    const cE = { cerrada:"#06D6A0", no_ejecutada:"#EF4444", pendiente:"#94A3B8" }[o.estado] || "#F59E0B";
                    return (
                      <tr key={i}>
                        <td style={tdS(i)}><span style={{ fontWeight: 700 }}>{o.consecutivo}</span></td>
                        <td style={tdS(i)}><span style={{ padding:"2px 8px", borderRadius:8, fontSize:10, fontWeight:700, color:cE, background:cE+"15" }}>{o.estado.replace("_"," ")}</span></td>
                        <td style={{ ...tdS(i), textTransform:"capitalize" }}>{o.tipo_servicio}</td>
                        <td style={{ ...tdS(i), maxWidth:120, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{o.cliente_nombre}</td>
                        <td style={{ ...tdS(i), color:C.muted }}>{o.referencia_nombre}</td>
                        <td style={{ ...tdS(i), color:C.muted }}>{o.tecnico_nombre || "-"}</td>
                        <td style={{ ...tdS(i), fontWeight:600, color:"#06D6A0", whiteSpace:"nowrap" }}>
                          {o.duracion_min ? `${Math.floor(o.duracion_min/60)}h ${Math.round(o.duracion_min%60)}m` : "-"}
                        </td>
                        <td style={{ ...tdS(i), color:C.muted, whiteSpace:"nowrap" }}>
                          {o.fecha_creacion ? new Date(o.fecha_creacion).toLocaleDateString("es-CO") : "-"}
                        </td>
                        <td style={tdS(i)}>
                          {(o.estado==="cerrada"||o.estado==="no_ejecutada") && (
                            <Btn variant="ghost" disabled={descargando===o.id}
                              onClick={() => descargarPDFOrden(o)}
                              style={{ fontSize:10, padding:"4px 10px" }}>
                              {descargando===o.id ? "..." : "PDF"}
                            </Btn>
                          )}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </Card>
        </div>
      )}

      {/* TAB ASISTENCIA */}
      {tab === "asistencia" && (
        <div>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
            <div style={{ fontSize: 13, color: C.muted }}>Marcaciones de hoy: <strong>{asistencia.length}</strong></div>
            <Btn variant="ghost" style={{ fontSize: 11 }}
              onClick={() => exportarCSV(asistencia.map(a => ({
                usuario:a.usuario, tipo_marca:a.tipo_marca, hora:a.hora, placa:a.placa||"", es_extra:a.es_extra?"Si":"No"
              })), "asistencia")}>Exportar CSV</Btn>
          </div>
          <Card>
            {asistencia.length === 0 ? (
              <div style={{ textAlign: "center", padding: 30, color: C.muted }}>No hay marcaciones hoy</div>
            ) : (
              <div style={{ overflowX: "auto" }}>
                <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
                  <thead>
                    <tr style={{ background: C.bg }}>
                      {["Usuario","Tipo","Hora","Vehiculo","Extra"].map(h => <th key={h} style={thS}>{h}</th>)}
                    </tr>
                  </thead>
                  <tbody>
                    {asistencia.map((a, i) => {
                      const cT = a.tipo_marca==="INICIO"?"#06D6A0":a.tipo_marca==="CIERRE"?"#EF4444":"#F59E0B";
                      return (
                        <tr key={i}>
                          <td style={{ ...tdS(i), fontWeight:600 }}>{a.usuario}</td>
                          <td style={tdS(i)}>
                            <span style={{ padding:"2px 8px", borderRadius:8, fontSize:10, fontWeight:700, color:cT, background:cT+"15" }}>{a.tipo_marca}</span>
                          </td>
                          <td style={tdS(i)}>{a.hora}</td>
                          <td style={{ ...tdS(i), color:C.muted }}>{a.placa||"-"}</td>
                          <td style={tdS(i)}>
                            {a.es_extra && <span style={{ padding:"2px 8px", borderRadius:8, fontSize:10, fontWeight:700, color:"#F59E0B", background:"#F59E0B15" }}>+{a.minutos_extra||0}min</span>}
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            )}
          </Card>
        </div>
      )}

      {/* TAB HORAS EXTRA */}
      {tab === "horas" && (
        <div>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
            <div style={{ fontSize: 13, color: C.muted }}>
              {horasExtra.length} registro(s)  |  Total: <strong>{fmt(totalExtra)}</strong>
            </div>
            <Btn variant="ghost" style={{ fontSize: 11 }}
              onClick={() => exportarCSV(horasExtra.map(h => ({
                empleado:h.empleado, fecha:h.fecha,
                horas_diurnas:h.horas_extra_diurnas, horas_nocturnas:h.horas_extra_nocturnas,
                valor_diurno:h.valor_diurno, valor_nocturno:h.valor_nocturno, total:h.total_a_pagar
              })), "horas-extra")}>Exportar CSV</Btn>
          </div>
          <Card>
            {horasExtra.length === 0 ? (
              <div style={{ textAlign: "center", padding: 30, color: C.muted }}>No hay horas extra en el periodo</div>
            ) : (
              <div style={{ overflowX: "auto" }}>
                <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
                  <thead>
                    <tr style={{ background: C.bg }}>
                      {["Empleado","Fecha","H.Diurnas","H.Nocturnas","Valor Diurno","Valor Nocturno","Total"].map(h => <th key={h} style={thS}>{h}</th>)}
                    </tr>
                  </thead>
                  <tbody>
                    {horasExtra.map((h, i) => (
                      <tr key={i}>
                        <td style={{ ...tdS(i), fontWeight:600 }}>{h.empleado}</td>
                        <td style={{ ...tdS(i), color:C.muted }}>{h.fecha}</td>
                        <td style={tdS(i)}>{h.horas_extra_diurnas||0}h</td>
                        <td style={tdS(i)}>{h.horas_extra_nocturnas||0}h</td>
                        <td style={{ ...tdS(i), fontWeight:600, color:"#06D6A0" }}>{fmt(h.valor_diurno)}</td>
                        <td style={{ ...tdS(i), fontWeight:600, color:"#8B5CF6" }}>{fmt(h.valor_nocturno)}</td>
                        <td style={{ ...tdS(i), fontWeight:800, color:C.dark }}>{fmt(h.total_a_pagar)}</td>
                      </tr>
                    ))}
                  </tbody>
                  <tfoot>
                    <tr style={{ borderTop:`2px solid ${C.border}`, background:C.bg }}>
                      <td colSpan={4} style={{ padding:"10px 12px", fontWeight:700 }}>TOTALES</td>
                      <td style={{ padding:"10px 12px", fontWeight:800, color:"#06D6A0" }}>{fmt(horasExtra.reduce((a,h)=>a+(h.valor_diurno||0),0))}</td>
                      <td style={{ padding:"10px 12px", fontWeight:800, color:"#8B5CF6" }}>{fmt(horasExtra.reduce((a,h)=>a+(h.valor_nocturno||0),0))}</td>
                      <td style={{ padding:"10px 12px", fontWeight:900, color:C.dark, fontSize:13 }}>{fmt(totalExtra)}</td>
                    </tr>
                  </tfoot>
                </table>
              </div>
            )}
          </Card>
        </div>
      )}
    </div>
  );
};

export default Reportes;
